<#
.SYNOPSIS
  Evaluates observed critical-error correlation for a candidate model/Agent team.
#>
param([Parameter(Mandatory=$true)][string]$InputPath,[switch]$PassThru)
$ErrorActionPreference='Stop';$x=Get-Content -LiteralPath $InputPath -Raw -Encoding UTF8|ConvertFrom-Json;$issues=[System.Collections.Generic.List[string]]::new();$members=@($x.members);if($members.Count-lt2){[void]$issues.Add('two_candidates_required')};foreach($member in $members){if([string]::IsNullOrWhiteSpace([string]$member.id)){[void]$issues.Add('member_id_required')};if([string]::IsNullOrWhiteSpace([string]$member.error_group)){[void]$issues.Add('member_error_group_required')}};if(@($members.id|Sort-Object -Unique).Count-ne$members.Count){[void]$issues.Add('member_ids_must_be_unique')};if(@($members.error_group|Sort-Object -Unique).Count-lt2){[void]$issues.Add('distinct_error_groups_required')}
$expectedPairs=[System.Collections.Generic.HashSet[string]]::new([StringComparer]::OrdinalIgnoreCase);for($i=0;$i-lt$members.Count;$i++){for($j=$i+1;$j-lt$members.Count;$j++){[void]$expectedPairs.Add((@([string]$members[$i].id,[string]$members[$j].id)|Sort-Object)-join'|')}};$seenPairs=[System.Collections.Generic.HashSet[string]]::new([StringComparer]::OrdinalIgnoreCase);$reselect=$false;$insufficient=$false;foreach($pair in @($x.pairwise_correlations)){$key=(@([string]$pair.left,[string]$pair.right)|Sort-Object)-join'|';if(-not$expectedPairs.Contains($key)){[void]$issues.Add('unknown_or_self_pair')};if(-not$seenPairs.Add($key)){[void]$issues.Add('duplicate_pair')};if([int]$pair.sample_size-lt0){[void]$issues.Add('invalid_sample_size')};if([double]$pair.critical_error_correlation-lt0-or[double]$pair.critical_error_correlation-gt1){[void]$issues.Add('invalid_correlation')};if([int]$pair.sample_size-lt5){$insufficient=$true};if([int]$pair.sample_size-ge5-and[double]$pair.critical_error_correlation-ge0.70){$reselect=$true}};foreach($key in $expectedPairs){if(-not$seenPairs.Contains($key)){[void]$issues.Add('pairwise_history_incomplete')}}
$status=if($issues.Count){'rejected'}elseif($reselect){'reselect_required'}elseif($insufficient){'shadow_only_insufficient_history'}else{'eligible_as_independent_candidates'};$r=[ordered]@{status=$status;task_type=$x.task_type;issues=@($issues);permission_change='none';budget_change='none';production_authority='none';external_calls=$false};if($PassThru){$r|ConvertTo-Json -Depth 6}else{[pscustomobject]$r|Format-List};if($issues.Count){exit 1}
